def _ordered_unique(items: Iterable[str]) -> List[str]:
    seen = set()
    ordered: List[str] = []
    for item in items:
        if item not in seen:
            ordered.append(item)
            seen.add(item)
    return ordered


def _benchmark_metrics(benchmark_key: str) -> Dict[str, Sequence[str]]:
    benchmark = build_benchmark(benchmark_key)
    metric_names_by_task = getattr(benchmark, "metric_names_by_task", {})
    return {task: list(metrics) for task, metrics in metric_names_by_task.items()}


def benchmark_catalog_alignment_issues() -> List[str]:
    issues: List[str] = []
    registered = set(available_benchmarks())

    for entry in BENCHMARK_CATALOG_ENTRIES:
        if entry.benchmark_key not in registered:
            issues.append(
                "Benchmark '{name}' is documented but not registered.".format(
                    name=entry.benchmark_key
                )
            )
            continue

        metric_names_by_task = _benchmark_metrics(entry.benchmark_key)
        if not metric_names_by_task:
            issues.append(
                "Benchmark '{name}' should declare metric_names_by_task for docs generation.".format(
                    name=entry.benchmark_key
                )
            )

        for task in metric_names_by_task:
            if not has_hazard_task(task):
                issues.append(
                    "Benchmark '{name}' declares unknown hazard task '{task}'.".format(
                        name=entry.benchmark_key,
                        task=task,
                    )
                )

        for config_path in entry.smoke_configs:
            path = REPO_ROOT / config_path
            if not path.exists():
                issues.append("Smoke config does not exist: {path}".format(path=config_path))
                continue
            config = load_experiment_config(path)
            if config.benchmark.name != entry.benchmark_key:
                issues.append(
                    "Smoke config '{path}' targets benchmark '{actual}', expected '{expected}'.".format(
                        path=config_path,
                        actual=config.benchmark.name,
                        expected=entry.benchmark_key,
                    )
                )
            if config.benchmark.hazard_task not in metric_names_by_task:
                issues.append(
                    "Smoke config '{path}' uses hazard task '{task}' not declared by benchmark '{name}'.".format(
                        path=config_path,
                        task=config.benchmark.hazard_task,
                        name=entry.benchmark_key,
                    )
                )

    return issues


def render_benchmark_page() -> str:
    lines: List[str] = [
        GENERATED_MARKER,
        "",
        "Benchmarks",
        "===================",
        "",
        "Overview",
        "--------",
        "",
        "Use this page to browse the implemented benchmark families, see which",
        "hazard tasks are covered today, and find the smoke configs that exercise",
        "each evaluation path. These rows describe current runnable coverage, not",
        "full roadmap parity. Use :doc:`appendix_a_coverage` for the audited",
        "method, benchmark, and dataset gap list.",
        "",
        "Implemented Benchmarks",
        "----------------------",
        "",
        "The summary below is generated from registered benchmark families,",
        "canonical hazard tasks, and the smoke configs under",
        "``pyhazards/configs/*/*_smoke.yaml``.",
        "",
        ".. list-table::",
        "   :widths: 16 20 18 20 22 34",
        "   :header-rows: 1",
        "   :class: dataset-list",
        "",
        "   * - Hazard Family",
        "     - Benchmark",
        "     - Implemented Tasks",
        "     - Key Metrics",
        "     - Smoke Configs",
        "     - Current Backing",
    ]

    for entry in BENCHMARK_CATALOG_ENTRIES:
        benchmark = build_benchmark(entry.benchmark_key)
        metric_names_by_task = _benchmark_metrics(entry.benchmark_key)
        tasks = list(metric_names_by_task.keys())
        metrics = _ordered_unique(
            metric for task in tasks for metric in metric_names_by_task.get(task, [])
        )
        config_names = [Path(path).name for path in entry.smoke_configs]

        lines.extend(
            [
                "   * - {hazard_family}".format(hazard_family=entry.hazard_family),
                "     - ``{class_name}`` (``{benchmark_key}``)".format(
                    class_name=benchmark.__class__.__name__,
                    benchmark_key=entry.benchmark_key,
                ),
                "     - {tasks}".format(
                    tasks=", ".join("``{task}``".format(task=task) for task in tasks)
                ),
                "     - {metrics}".format(
                    metrics=", ".join("``{metric}``".format(metric=metric) for metric in metrics)
                ),
                "     - {configs}".format(
                    configs=", ".join("``{name}``".format(name=name) for name in config_names)
                ),
                "     - {backing}".format(backing=entry.current_backing),
            ]
        )

    lines.extend(
        [
            "",
            "Hurricane baselines use the shared tropical-cyclone benchmark family",
            "and are exercised through the ``tc.track_intensity`` smoke configs.",
            "",
            "Typical Usage",
            "-------------",
            "",
            ".. code-block:: python",
            "",
            "    from pyhazards.configs import load_experiment_config",
            "    from pyhazards.engine import BenchmarkRunner",
            "",
            '    config = load_experiment_config("pyhazards/configs/earthquake/phasenet_smoke.yaml")',
            "    summary = BenchmarkRunner().run(config)",
            "    print(summary.metrics)",
            "",
            "Command-Line Entry Point",
            "------------------------",
            "",
            "Use ``python scripts/run_benchmark.py --help`` to inspect the shared",
            "benchmark runner CLI and list available hazard tasks.",
            "",
            "Next step: pair this page with :doc:`pyhazards_configs` when you want",
            "to author experiment YAML files and :doc:`pyhazards_reports` when you",
            "want to export comparable benchmark summaries.",
            "",
        ]
    )
    return "\n".join(lines)


def sync_generated_benchmark_docs(check: bool = False) -> List[Path]:
    content = render_benchmark_page()
    current = BENCHMARK_PAGE_PATH.read_text(encoding="utf-8") if BENCHMARK_PAGE_PATH.exists() else None
    if current == content:
        return []
    if not check:
        BENCHMARK_PAGE_PATH.parent.mkdir(parents=True, exist_ok=True)
        BENCHMARK_PAGE_PATH.write_text(content, encoding="utf-8")
    return [BENCHMARK_PAGE_PATH]


__all__ = [
    "BENCHMARK_PAGE_PATH",
    "benchmark_catalog_alignment_issues",
    "render_benchmark_page",
    "sync_generated_benchmark_docs",
]
